import React, { useState, useEffect, useRef } from "react";
import { supabase, BUCKET_FOTOS } from "./supabase.js";

// ============================================================
// CONFIGURAÇÃO — edite aqui os dados da loja
// ============================================================
const WHATSAPP_NUMERO = "5577988620541"; // 77 98862-0541
const WHATSAPP_EXIBIR = "(77) 98862-0541";
const SENHA_VENDEDOR = "alexCHIO";
const NOME_LOJA = "ELA";
const SUBTITULO = "Semijoias";
const INSTAGRAM = "https://instagram.com/";
const FRETE_GRATIS_ACIMA = 299.9;
const AVISO_TOPO = [
  "Frete grátis acima de R$299,90",
  "Garantia de 6 meses",
  "Parcele em até 6x no WhatsApp",
];

// Categorias da vitrine (o vendedor escolhe uma ao cadastrar)
const CATEGORIAS = [
  "Brincos",
  "Colares",
  "Anéis",
  "Pulseiras",
  "Cintos",
  "Conjuntos",
  "Pingentes",
];

// Fotos da loja (Sobre nós)
const FOTO_LOJA = "data:image/jpeg;base64,";
const FOTO_SACOLA = "data:image/jpeg;base64,";

// ============================================================
// ============================================================
// UTILITÁRIOS
// ============================================================
const brl = (v) =>
  v.toLocaleString("pt-BR", { style: "currency", currency: "BRL" });

const store = {
  get(key, fallback) {
    try {
      const raw = localStorage.getItem(key);
      return raw ? JSON.parse(raw) : fallback;
    } catch {
      return fallback;
    }
  },
  set(key, val) {
    try {
      localStorage.setItem(key, JSON.stringify(val));
    } catch {}
  },
};

// ============================================================
// APP
// ============================================================
export default function App() {
  const [tela, setTela] = useState("loja");
  const [produtos, setProdutos] = useState([]);
  const [carregandoProdutos, setCarregandoProdutos] = useState(true);
  const [carrinho, setCarrinho] = useState(() => store.get("sj_carrinho", {}));
  const [cliente, setCliente] = useState(() =>
    store.get("sj_cliente", { nome: "", telefone: "", endereco: "" })
  );
  const [carrinhoAberto, setCarrinhoAberto] = useState(false);
  const [filtro, setFiltro] = useState("Todos");
  const [menuAberto, setMenuAberto] = useState(false);

  // Carrega os produtos do Supabase quando o site abre
  const carregarProdutos = async () => {
    setCarregandoProdutos(true);
    const { data, error } = await supabase
      .from("produtos")
      .select("*")
      .order("criado_em", { ascending: false });
    if (!error && data) setProdutos(data);
    setCarregandoProdutos(false);
  };

  useEffect(() => {
    carregarProdutos();
  }, []);

  useEffect(() => {
    document.body.style.overflow = menuAberto ? "hidden" : "";
    return () => {
      document.body.style.overflow = "";
    };
  }, [menuAberto]);

  const irCategoria = (cat) => {
    setFiltro(cat);
    setTela("loja");
    setMenuAberto(false);
    setTimeout(() => {
      document.getElementById("vitrine")?.scrollIntoView({ behavior: "smooth" });
    }, 60);
  };

  const irSecao = (id) => {
    setTela("loja");
    setMenuAberto(false);
    setTimeout(() => {
      document.getElementById(id)?.scrollIntoView({ behavior: "smooth" });
    }, 60);
  };

  // Carrinho e dados do cliente continuam salvos no navegador de cada visitante
  useEffect(() => store.set("sj_carrinho", carrinho), [carrinho]);
  useEffect(() => store.set("sj_cliente", cliente), [cliente]);

  const qtdTotal = Object.values(carrinho).reduce((a, b) => a + b, 0);

  const addCarrinho = (id) => {
    setCarrinho((c) => ({ ...c, [id]: (c[id] || 0) + 1 }));
    setCarrinhoAberto(true);
  };
  const setQtd = (id, q) =>
    setCarrinho((c) => {
      const n = { ...c };
      if (q <= 0) delete n[id];
      else n[id] = q;
      return n;
    });

  return (
    <div style={S.root}>
      <FonteEEstilos />

      {tela === "loja" && <BarraAvisos />}

      <Header
        tela={tela}
        setTela={setTela}
        qtdTotal={qtdTotal}
        onCarrinho={() => setCarrinhoAberto(true)}
        filtro={filtro}
        setFiltro={setFiltro}
        onAbrirMenu={() => setMenuAberto(true)}
        irCategoria={irCategoria}
        irSecao={irSecao}
      />

      {menuAberto && (
        <MenuLateral
          onFechar={() => setMenuAberto(false)}
          irCategoria={irCategoria}
          irSecao={irSecao}
          setTela={setTela}
        />
      )}

      {tela === "loja" && <FaixaPromo />}

      {tela === "loja" ? (
        <Loja
          produtos={produtos}
          carregando={carregandoProdutos}
          carrinho={carrinho}
          addCarrinho={addCarrinho}
          filtro={filtro}
          setFiltro={setFiltro}
        />
      ) : (
        <PainelVendedor
          produtos={produtos}
          recarregar={carregarProdutos}
        />
      )}

      {tela === "loja" && carrinhoAberto && (
        <Carrinho
          produtos={produtos}
          carrinho={carrinho}
          setQtd={setQtd}
          cliente={cliente}
          setCliente={setCliente}
          onClose={() => setCarrinhoAberto(false)}
          limpar={() => setCarrinho({})}
        />
      )}

      {tela === "loja" && <Rodape setTela={setTela} />}
    </div>
  );
}

