// ============================================================
// FAIXA PROMOCIONAL ROLANTE
// ============================================================
function FaixaPromo() {
  const txt = `FRETE GRÁTIS ACIMA DE ${brl(FRETE_GRATIS_ACIMA)}`;
  const repetido = Array(8).fill(txt);
  return (
    <div style={S.faixa}>
      <div style={S.faixaTrack}>
        {[...repetido, ...repetido].map((t, i) => (
          <span key={i} style={S.faixaItem}>
            {t} <span style={{ opacity: 0.4 }}>◇</span>
          </span>
        ))}
      </div>
    </div>
  );
}

